parameters.text:
=Ти класифікатор Inbox Agent. Аналізуй матеріали будь-якою мовою і поверни тільки структурований результат за підключеною JSON-схемою.

Мовні правила:
- title, summary, key_points і next_actions завжди формуй українською мовою, незалежно від мови джерела;
- language — ISO-код мови оригінального матеріалу, а не мови відповіді;
- власні назви, моделі, технічні терміни та числа не спотворюй під час перекладу.

Правила аналізу:
- обирай рівно одне значення з кожного дозволеного списку;
- якщо немає чіткої відповідності, використовуй Other;
- priority за замовчуванням Medium;
- tags: 3–10 коротких тегів без символу #;
- key_points: до 12 найважливіших тез українською; для відео починай тезу з реального таймкоду у форматі HH:MM:SS — лише якщо таймкод є у транскрипті або розділах, ніколи не вигадуй його;
- next_actions: максимум 5 конкретних дій українською, порожній масив якщо дії не потрібні;
- не додавай фактів, яких немає у матеріалі;
- якщо транскрипт недоступний, прямо зазнач це у summary та аналізуй лише доступні метадані.

Дозволені категорії: {{ $json.categories.join(', ') }}
Дозволені проєкти: {{ $json.projects.join(', ') }}
Дозволені типи: {{ $json.item_types.join(', ') }}
Дозволені пріоритети: {{ $json.priorities.join(', ') }}

Тип вхідних даних: {{ $json.content_type }}
URL: {{ $json.source_url || 'немає' }}
Матеріал:
{{ $json.normalized_text }}

parameters.jsCode:
const source = $('Load Inbox Item').item.json;
const analysis = $json.output || $json;
const categories = new Set(source.categories);
const projects = new Set(source.projects);
const itemTypes = new Set(source.item_types);
const priorities = new Set(source.priorities);

const cleanList = (value, limit) => [...new Set((Array.isArray(value) ? value : [])
  .map((entry) => String(entry).trim().replace(/^#+/, ''))
  .filter(Boolean))].slice(0, limit);

return [{ json: {
  item_id: source.item_id,
  user_id: source.user_id,
  title: String(analysis.title || source.normalized_text.slice(0, 120)).trim().slice(0, 160),
  summary: String(analysis.summary || source.normalized_text.slice(0, 500)).trim().slice(0, 1000),
  content: source.normalized_text,
  source_url: source.source_url || null,
  category: categories.has(analysis.category) ? analysis.category : 'Other',
  project: projects.has(analysis.project) ? analysis.project : 'Other',
  item_type: itemTypes.has(analysis.type) ? analysis.type : 'Idea',
  priority: priorities.has(analysis.priority) ? analysis.priority : 'Medium',
  tags: cleanList(analysis.tags, 12),
  key_points: cleanList(analysis.key_points, 12),
  next_actions: cleanList(analysis.next_actions, 5),
  language: String(analysis.language || 'uk').trim().slice(0, 8)
} }];

const analysis = $('Validate Classification').item.json;
const source = $('Load Inbox Item').item.json;
if (!source.chat_id) return [];
const points = (analysis.key_points || []).slice(0, 8);
const actions = (analysis.next_actions || []).slice(0, 3);
const sections = [
  `✅ Аналіз завершено\n\n🧠 ${analysis.title}`,
  analysis.summary,
  `📁 Проєкт: ${analysis.project}\n🏷 Категорія: ${analysis.category}\n📌 Тип: ${analysis.item_type}\n⚡ Пріоритет: ${analysis.priority}\n🌐 Мова джерела: ${analysis.language}`,
  points.length ? `🔑 Ключові моменти:\n${points.map((point) => `• ${point}`).join('\n')}` : '',
  actions.length ? `➡️ Наступні дії:\n${actions.map((action) => `• ${action}`).join('\n')}` : '',
  $json.indexing_enqueued ? '🧩 RAG: додано до послідовної черги індексації.' : '🧩 RAG: матеріал уже стоїть у черзі або проіндексований.',
  analysis.source_url ? `🔗 ${analysis.source_url}` : ''
].filter(Boolean);
return [{ json: { chat_id: source.chat_id, reply: sections.join('\n\n').slice(0, 4000) } }];
